dashboard.definition:
{
    "visualizations": {
        "viz_RHNg7sxE": {
            "type": "splunk.table",
            "options": {
                "drilldown": "none",
                "showInternalFields": false,
                "count": 5
            },
            "dataSources": {
                "primary": "ds_evbDgF3H"
            },
            "title": "Utilization % per port",
            "showProgressBar": true,
            "description": "This panel shows how much bandwidth each network port in the chassis is using. It skips internal or unused ports, so you only see real traffic. This helps you quickly spot which ports are heavily used and if there might be any network slowdowns."
        },
        "viz_tCkRBBzI": {
            "type": "splunk.bar",
            "options": {
                "yAxisAbbreviation": "off",
                "y2AxisAbbreviation": "off",
                "showRoundedY2AxisLabels": false,
                "legendTruncation": "ellipsisMiddle",
                "showY2MajorGridLines": true,
                "showSplitSeries": false
            },
            "dataSources": {
                "primary": "ds_Tcau3P6l"
            },
            "eventHandlers": [
                {
                    "type": "drilldown.setToken",
                    "options": {
                        "tokens": [
                            {
                                "token": "eth_transmit_util_chassis",
                                "key": "row.Server Name.value"
                            }
                        ]
                    }
                }
            ],
            "title": "Ethernet Transmit utilization per Server (Sum)",
            "showProgressBar": true,
            "description": "This panel displays the total Ethernet transmit utilization per server within the chassis, using the network_io_transmit metric. It helps identify server-wise outbound traffic patterns, providing insights into network load distribution and potential hotspots across connected servers."
        },
