    "dataSources": {
        "ds_MRht5eW9": {
            "type": "ds.search",
            "options": {
                "query": "| tstats values(cisco_intersight.cisco_intersight_network.network_domain_name) as DomainName \n         values(cisco_intersight.cisco_intersight_network.network_domain_id) as DomainId \n  from datamodel=Cisco_Intersight \n  where nodename=cisco_intersight.cisco_intersight_network \n        AND cisco_intersight.cisco_intersight_network.network_domain_name=*\n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n  by cisco_intersight.cisco_intersight_network.network_domain_id, \"cisco_intersight.cisco_intersight_network.network_account_name\"\n\n| rename DomainName as \"event.DomainName\", DomainId as \"event.DomainId\"\n| table event.DomainName, event.DomainId",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "name": "Select Domains search"
        },
        "ds_LU3nqIRB": {
            "type": "ds.search",
            "options": {
                "query": "| tstats values(cisco_intersight.cisco_intersight_network.network_chassis) as Chassis\n  from datamodel=Cisco_Intersight \n  where nodename=cisco_intersight.cisco_intersight_network \n        AND cisco_intersight.cisco_intersight_network.network_domain_id IN ($select_domain$), cisco_intersight.cisco_intersight_network.network_chassis!=null\n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n  by cisco_intersight.cisco_intersight_network.network_domain_id, cisco_intersight.cisco_intersight_network.network_chassis, cisco_intersight.cisco_intersight_network.network_account_name\n| dedup Chassis\n| rex field=Chassis \"/api/v1/equipment/Chasses/(?<chassis_id>[^/]+)\"\n| join type=left chassis_id [ | inputlookup cisco_intersight_equipment_chasses | where splunk_managed_lifecycle == \"PRESENT\" | rename Moid as chassis_id, Name as chassis_name | table chassis_id, chassis_name ]\n| table Chassis, chassis_name",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "name": "Select Chassis search"
        },
        "ds_evbDgF3H": {
            "type": "ds.search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count\n       avg(\"cisco_intersight.cisco_intersight_network.network_bandwidth_receive_utilization_avg\") as total_nura,\n       max(\"cisco_intersight.cisco_intersight_network.network_bandwidth_receive_utilization_max\") as total_nurmx,\n       avg(\"cisco_intersight.cisco_intersight_network.network_bandwidth_transmit_utilization_avg\") as total_nuta,\n       max(\"cisco_intersight.cisco_intersight_network.network_bandwidth_transmit_utilization_max\") as total_nutmx\n       from datamodel=Cisco_Intersight\n       where nodename=cisco_intersight.cisco_intersight_network\n       AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n       AND \"cisco_intersight.cisco_intersight_network.network_domain_id\" IN ($select_domain$)\n       AND cisco_intersight.cisco_intersight_network.network_chassis != null\n       AND \"cisco_intersight.cisco_intersight_network.network_chassis\" IN ($select_chassis$)\n       AND NOT \"cisco_intersight.cisco_intersight_network.network_port_role\" IN (\"unconfigured\", \"server_pc\", \"fabric_pc\", \"host_pc\", \"vethernet\", \"vfc\", \"vnic\", \"vhba\", \"eth_uplink_pc\")\n       by \"cisco_intersight.cisco_intersight_network.network_domain_name\",\n          \"cisco_intersight.cisco_intersight_network.network_domain_id\",\n          \"cisco_intersight.cisco_intersight_network.network_host_name\",\n          \"cisco_intersight.cisco_intersight_network.network_id\",\n          \"cisco_intersight.cisco_intersight_network.network_chassis\",\n          \"cisco_intersight.cisco_intersight_network.network_chassis_number\",\n          \"cisco_intersight.cisco_intersight_network.network_name\", \n          \"cisco_intersight.cisco_intersight_network.network_port_role\"\n          \"cisco_intersight.cisco_intersight_network.network_account_moid\",\n          \"cisco_intersight.cisco_intersight_network.network_account_name\"\n\n| where \"$show_zero_values$\"=\"true\" \n   OR (round(total_nura * 100, 2) > 0 \n       and round(total_nurmx * 100, 2) > 0 \n       and round(total_nuta * 100, 2) > 0 \n       and round(total_nutmx * 100, 2) > 0)\n\n| eval total_nura = round(total_nura * 100, 2) . \"%\"\n| eval total_nurmx = round(total_nurmx * 100, 2) . \"%\"\n| eval total_nuta = round(total_nuta * 100, 2) . \"%\"\n| eval total_nutmx = round(total_nutmx * 100, 2) . \"%\"\n\n| eval 'cisco_intersight.cisco_intersight_network.network_chassis_number' = coalesce('cisco_intersight.cisco_intersight_network.network_chassis_number', \"\")\n\n| rex field=\"cisco_intersight.cisco_intersight_network.network_id\" \"/(?<Moid>[^/]+)$\"\n| eval _key='cisco_intersight.cisco_intersight_network.network_account_moid' + \"_\" + Moid\n\n| join type=left _key [\n    | inputlookup cisco_intersight_ether_hostports | where splunk_managed_lifecycle == \"PRESENT\"\n    | append [| inputlookup cisco_intersight_ether_networkports | where splunk_managed_lifecycle == \"PRESENT\"]\n    | append [| inputlookup cisco_intersight_ether_physicalports | where splunk_managed_lifecycle == \"PRESENT\"]\n    | fields _key PortId Dn OperSpeed OperState PortChannelId Role SwitchId\n]\n\n| rename \"cisco_intersight.cisco_intersight_network.network_domain_name\" as \"Domain Name\", \n         \"cisco_intersight.cisco_intersight_network.network_domain_id\" as event.DomainId, \"cisco_intersight.cisco_intersight_network.network_id\" as event_id, \"cisco_intersight.cisco_intersight_network.network_chassis_number\" as \"Chassis Number\", \"cisco_intersight.cisco_intersight_network.network_name\" as Name, \"cisco_intersight.cisco_intersight_network.network_port_role\" as \"Port Role\",\n         total_nura as \"Avg receive Utilization\", total_nuta as \"Avg Transmit Utilization\", total_nurmx as \"Max receive Utilization\", total_nutmx as \"Max transmit Utilization\", \"SwitchId\" as \"FI\"\n\n| table \"FI\", \"Chassis Number\", \"Port Role\", Name, Dn, OperSpeed, OperState, \"Avg Transmit Utilization\", \"Max transmit Utilization\", \"Avg receive Utilization\", \"Max receive Utilization\"\n| sort \"Port Role\"",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "name": "Chassis Utilization - Utilization _ per port search"
        },
        "ds_Tcau3P6l": {
            "type": "ds.search",
            "options": {
                "query": "| tstats `cisco_intersight_summariesonly`\n    sum(\"cisco_intersight.cisco_intersight_network.network_io_transmit\") as total_nits\n    from datamodel=Cisco_Intersight\n    where nodename = cisco_intersight.cisco_intersight_network\n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n        AND \"cisco_intersight.cisco_intersight_network.network_domain_id\" IN ($select_domain$)\n        AND cisco_intersight.cisco_intersight_network.network_chassis!=null\n        AND \"cisco_intersight.cisco_intersight_network.network_chassis\" IN ($select_chassis$)\n        AND \"cisco_intersight.cisco_intersight_network.network_server_id\" != \"\"\n        AND \"cisco_intersight.cisco_intersight_network.network_port_role\" = \"vnic\"\n    by \"cisco_intersight.cisco_intersight_network.network_server_id\",\n       \"cisco_intersight.cisco_intersight_network.network_domain_id\",\n       \"cisco_intersight.cisco_intersight_network.network_account_name\"\n\n| rename \n    \"cisco_intersight.cisco_intersight_network.network_domain_id\" as event.DomainId\n\n| search cisco_intersight.cisco_intersight_network.network_server_id=\"*Blades*\"\n\n| rex field=\"cisco_intersight.cisco_intersight_network.network_server_id\" \".*/(?<server_id>[^/]+)$\"\n\n| join type=left server_id [\n    | inputlookup cisco_intersight_compute_physicalsummaries | where splunk_managed_lifecycle == \"PRESENT\"\n    | rename \"Moid\" as server_id, \"Name\" as server_name\n]\n\n| where \"$show_zero_values$\"=\"true\" OR (total_nits != 0)\n\n| eval \"Transmit ($data_unit_transmit$)\" = `cisco_intersight_bytes_to_given_unit(total_nits,$data_unit_transmit$)`\n| sort server_name\n| rename server_name as \"Server Name\"\n| table \"Server Name\", \"Transmit ($data_unit_transmit$)\"",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                }
            },
            "name": "Ethernet Transmit utilization per Server _Sum_ 1 search"
        },
        "ds_weyuWeLm": {
            "type": "ds.search",
            "options": {
