                "query": "| tstats \n    avg(cisco_intersight.cisco_intersight_network.network_receive_utilization) as nura, \n    max(cisco_intersight.cisco_intersight_network.network_bandwidth_receive_utilization_max) as nurmx \n    from datamodel=Cisco_Intersight \n    where nodename=cisco_intersight.cisco_intersight_network \n        AND cisco_intersight.cisco_intersight_network.network_id = \"$receive_ifm_downlink_chassis$\"\n        AND cisco_intersight.cisco_intersight_network.network_port_role = \"host_port\"\n        AND cisco_intersight.cisco_intersight_network.network_port_type = \"backplane_port\"\n    by \n        cisco_intersight.cisco_intersight_network.network_name,\n        cisco_intersight.cisco_intersight_network.network_id,\n        _time\n\n| eval nura = round(nura * 100, 2)\n| eval nurmx = round(nurmx * 100, 2)\n\n| rename cisco_intersight.cisco_intersight_network.network_name as Name\n\n| $granularity$ \n    sum(nura) as \"Transmit Utilziation % per IFM downlink (avg)\", \n    sum(nurmx) as \"Transmit Utilziation % per IFM downlink (max)\" \n    by Name",
