work.network_id\" \"/(?<Moid>[^/]+)$\"\n| eval _key='cisco_intersight.cisco_intersight_network.network_account_moid' + \"_\" + Moid\n\n| join type=left _key [\n    | inputlookup cisco_intersight_ether_hostports | where splunk_managed_lifecycle == \"PRESENT\"\n    | fields _key PortId Dn OperSpeed OperState PortChannelId Role SwitchId\n]\n\n| rename \n    cisco_intersight.cisco_intersight_network.network_domain_name as \"Domain Name\",\n    cisco_intersight.cisco_intersight_network.network_port_role as \"Network Port Role\",\n    cisco_intersight.cisco_intersight_network.network_name as \"Port Name\",\n    cisco_intersight.cisco_intersight_network.network_chassis_number as Chassis,\n    cisco_intersight.cisco_intersight_network.network_chassis as _hwchassis,\n    nrps as Ethernet,\n    total_congestion as \"Total Congestion\"\n    nprppps as FC, \"SwitchId\" as \"FI\",\n\n| table \"Domain Name\", \"FI\", Chassis, \"Network Port Role\", \"Port Name\", \"Dn\", \"OperSpeed\", \"OperState\", \"Total Congestion\", \"Ethernet\", \"FC\", _hwchassis\n\n| sort \"Network Port Role\"",
